      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('../../lib/id');

let tasksStore = [];

async function getTasksByStatus(status) {
  if (status) {
    return tasksStore.filter(task => task.status === status);
  }
  return tasksStore;
}

async function updateTaskStatus(taskId, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    throw new Error('TASK_NOT_FOUND');
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = {
  getTasksByStatus,
  updateTaskStatus
};
