  try {
    const member = await membersService.addMember(userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'MEMBER_EXISTS') {
      return sendError(res, 409, 'MEMBER_EXISTS', 'Member already exists');
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;
